from __future__ import annotations

from typing import Any


DIRECTIONS = {
    "up": (-1, 0),
    "down": (1, 0),
    "left": (0, -1),
    "right": (0, 1),
}


def move(simulation: Any, agent_id: str, direction: str) -> dict[str, Any]:
    agent = simulation.agent_states[agent_id]
    if direction not in DIRECTIONS:
        return {"success": False, "reason": f"Unknown direction `{direction}`."}

    row_delta, col_delta = DIRECTIONS[direction]
    next_position = (agent.position[0] + row_delta, agent.position[1] + col_delta)

    if not simulation.in_bounds(next_position):
        return {"success": False, "reason": "Move blocked by world boundary."}
    if next_position in simulation.walls:
        return {"success": False, "reason": "Move blocked by wall."}
    if next_position == simulation.door_position and not simulation.door_unlocked:
        return {"success": False, "reason": "Move blocked by locked door."}

    agent.position = next_position
    return {"success": True, "position": list(agent.position)}


def look(simulation: Any, agent_id: str) -> dict[str, Any]:
    return {
        "success": True,
        "visible_cells": simulation.get_visible_cells(agent_id),
    }


def pick_up(simulation: Any, agent_id: str, item: str) -> dict[str, Any]:
    agent = simulation.agent_states[agent_id]
    if item != "key":
        return {"success": False, "reason": f"Item `{item}` cannot be picked up."}
    if simulation.key_picked:
        return {"success": False, "reason": "The key is already gone."}
    if agent.position != simulation.key_position:
        return {"success": False, "reason": "Agent is not standing on the key."}

    simulation.key_picked = True
    agent.inventory.append("key")
    return {"success": True, "inventory": list(agent.inventory)}


def check_inventory(simulation: Any, agent_id: str) -> dict[str, Any]:
    agent = simulation.agent_states[agent_id]
    return {"success": True, "inventory": list(agent.inventory)}


def use_item(simulation: Any, agent_id: str, item: str, target: str) -> dict[str, Any]:
    agent = simulation.agent_states[agent_id]
    if item != "key" or target != "door":
        return {"success": False, "reason": "Only using the key on the door is supported."}
    if "key" not in agent.inventory:
        return {"success": False, "reason": "Agent does not have the key."}
    if _adjacent_or_same(agent.position, simulation.door_position) is False:
        return {"success": False, "reason": "Door is not close enough to unlock."}
    if simulation.door_unlocked:
        return {"success": False, "reason": "Door is already unlocked."}

    simulation.door_unlocked = True
    return {"success": True, "door_unlocked": True}


def send_message(simulation: Any, agent_id: str, agent: str, message: dict[str, Any]) -> dict[str, Any]:
    simulation.message_queue.append(
        {
            "from": agent_id,
            "to": agent,
            "message": message,
            "deliver_on_turn": simulation.turn_index + 1,
        }
    )
    return {"success": True, "queued_for": agent, "message": message}


def _adjacent_or_same(a: tuple[int, int], b: tuple[int, int]) -> bool:
    return abs(a[0] - b[0]) + abs(a[1] - b[1]) <= 1

from __future__ import annotations

import json
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any


@dataclass
class StepLog:
    step: int
    agent_id: str
    observation: dict[str, Any]
    thought: str | None
    action: str
    tool_input: dict[str, Any]
    tool_output: dict[str, Any]
    result_state: dict[str, Any]
    belief_state: dict[str, Any]
    ground_truth: dict[str, Any]
    delivered_messages: list[dict[str, Any]]
    latency_ms: float | None = None


@dataclass
class SimulationLogger:
    run_id: str
    history: list[StepLog] = field(default_factory=list)
    events: list[dict[str, Any]] = field(default_factory=list)

    def log_step(self, entry: StepLog) -> None:
        self.history.append(entry)

    def log_event(self, event: dict[str, Any]) -> None:
        self.events.append(event)

    def export_json(self, path: str | Path, summary: dict[str, Any]) -> None:
        payload = {
            "run_id": self.run_id,
            "summary": summary,
            "events": self.events,
            "steps": [self._serialize_step(step) for step in self.history],
        }
        output_path = Path(path)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        output_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")

    def _serialize_step(self, step: StepLog) -> dict[str, Any]:
        return {
            "step": step.step,
            "agent_id": step.agent_id,
            "observation": step.observation,
            "thought": step.thought,
            "action": step.action,
            "tool_input": step.tool_input,
            "tool_output": step.tool_output,
            "result_state": step.result_state,
            "belief_state": step.belief_state,
            "ground_truth": step.ground_truth,
            "delivered_messages": step.delivered_messages,
            "latency_ms": step.latency_ms,
        }


def build_analysis_report(history: list[StepLog], summary: dict[str, Any]) -> str:
    lines = [
        f"Run status: {summary['status']}",
        f"Total turns: {summary['steps']}",
        "What happened:",
    ]

    for event in summary.get("major_events", []):
        lines.append(f"- step {event['step']}: {event['description']}")

    lines.append("Why it happened:")
    repeated = _detect_repeated_actions(history)
    if repeated:
        for item in repeated:
            lines.append(f"- {item}")
    else:
        lines.append("- No severe action loops detected.")

    divergence = _detect_belief_divergence(history)
    if divergence:
        lines.append("What should change:")
        for item in divergence:
            lines.append(f"- {item}")
    else:
        lines.append("What should change:")
        lines.append("- Beliefs stayed close to reality; focus next on richer coordination strategies.")

    return "\n".join(lines)


def _detect_repeated_actions(history: list[StepLog]) -> list[str]:
    findings: list[str] = []
    by_agent: dict[str, list[str]] = {}
    for step in history:
        by_agent.setdefault(step.agent_id, []).append(step.action)

    for agent_id, actions in by_agent.items():
        for index in range(len(actions) - 2):
            window = actions[index : index + 3]
            if len(set(window)) == 1:
                findings.append(
                    f"Agent {agent_id} repeated `{window[0]}` three turns in a row near step {index + 1}."
                )
                break
    return findings


def _detect_belief_divergence(history: list[StepLog]) -> list[str]:
    findings: list[str] = []
    for step in history:
        belief = step.belief_state
        truth = step.ground_truth
        if belief.get("key_position") and tuple(belief["key_position"]) != tuple(truth["key_position"]):
            findings.append(
                f"Agent {step.agent_id} believed the key was at {belief['key_position']} during step {step.step},"
                f" but reality was {truth['key_position']}."
            )
            break
    return findings

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


DIRECTION_VECTORS = {
    "up": (-1, 0),
    "down": (1, 0),
    "left": (0, -1),
    "right": (0, 1),
}


@dataclass
class AgentAction:
    tool: str
    args: dict[str, Any]
    thought: str


@dataclass
class AgentState:
    agent_id: str
    position: tuple[int, int]
    inventory: list[str] = field(default_factory=list)
    inbox: list[dict[str, Any]] = field(default_factory=list)
    outbox: list[dict[str, Any]] = field(default_factory=list)
    belief: dict[str, Any] = field(
        default_factory=lambda: {
            "key_position": None,
            "door_position": None,
            "exit_position": None,
            "walls": [],
            "has_key": False,
            "teammate_last_position": None,
            "visited_positions": [],
        }
    )
    recent_actions: list[str] = field(default_factory=list)

    def remember_position(self, position: tuple[int, int]) -> None:
        visited = self.belief.setdefault("visited_positions", [])
        if position not in visited:
            visited.append(position)

    def note_action(self, action_name: str) -> None:
        self.recent_actions.append(action_name)
        if len(self.recent_actions) > 6:
            self.recent_actions.pop(0)


class DungeonAgent:
    """A simple, intentionally imperfect agent focused on traceability."""

    def __init__(self, state: AgentState, teammate_id: str) -> None:
        self.state = state
        self.teammate_id = teammate_id

    def observe(self, visible_cells: list[dict[str, Any]]) -> None:
        self.state.remember_position(self.state.position)
        for cell in visible_cells:
            position = tuple(cell["position"])
            cell_type = cell["cell_type"]
            if cell_type == "key":
                self.state.belief["key_position"] = position
            elif cell_type == "door":
                self.state.belief["door_position"] = position
            elif cell_type == "exit":
                self.state.belief["exit_position"] = position
            elif cell_type == "wall":
                walls = self.state.belief.setdefault("walls", [])
                if position not in walls:
                    walls.append(position)

        self.state.belief["has_key"] = "key" in self.state.inventory
        if self.state.inbox:
            self._process_messages()

    def choose_action(self, observation: dict[str, Any]) -> AgentAction:
        current_position = tuple(observation["self_position"])
        self.state.remember_position(current_position)

        for cell in observation["visible_cells"]:
            if tuple(cell["position"]) == current_position and cell["cell_type"] == "key":
                return AgentAction(
                    tool="pick_up",
                    args={"item": "key"},
                    thought="I am standing on the key, so I should pick it up.",
                )

        for cell in observation["visible_cells"]:
            if cell["cell_type"] == "door":
                if "key" in self.state.inventory and not cell.get("door_unlocked", False):
                    return AgentAction(
                        tool="use_item",
                        args={"item": "key", "target": "door"},
                        thought="The locked door is nearby and I have the key, so I should unlock it.",
                    )

        if self._should_send_message():
            message = self._compose_message()
            if message:
                return AgentAction(
                    tool="send_message",
                    args={"agent": self.teammate_id, "message": message},
                    thought="I learned something useful and should share it with my teammate.",
                )

        unseen_priority = self._preferred_direction(observation)
        if unseen_priority:
            return AgentAction(
                tool="move",
                args={"direction": unseen_priority},
                thought=f"I will explore by moving {unseen_priority}.",
            )

        return AgentAction(
            tool="look",
            args={},
            thought="I am uncertain about the next move, so I will refresh my local observation.",
        )

    def _process_messages(self) -> None:
        for message in self.state.inbox:
            kind = message.get("kind")
            if kind == "location_update":
                item = message.get("item")
                position = tuple(message["position"])
                if item == "key":
                    self.state.belief["key_position"] = position
                elif item == "door":
                    self.state.belief["door_position"] = position
                elif item == "exit":
                    self.state.belief["exit_position"] = position
            elif kind == "status_update":
                self.state.belief["teammate_last_position"] = tuple(message["position"])
        self.state.inbox.clear()

    def _should_send_message(self) -> bool:
        if not self.state.recent_actions:
            return True
        recent = self.state.recent_actions[-2:]
        return all(action != "send_message" for action in recent)

    def _compose_message(self) -> dict[str, Any] | None:
        for item_name, belief_key in [
            ("key", "key_position"),
            ("door", "door_position"),
            ("exit", "exit_position"),
        ]:
            if self.state.belief.get(belief_key) is not None:
                return {
                    "kind": "location_update",
                    "item": item_name,
                    "position": list(self.state.belief[belief_key]),
                }
        return {
            "kind": "status_update",
            "position": list(self.state.position),
        }

    def _preferred_direction(self, observation: dict[str, Any]) -> str | None:
        walkable_neighbors = {
            cell["direction"]: cell
            for cell in observation["visible_cells"]
            if cell["direction"] in DIRECTION_VECTORS and cell["is_walkable"]
        }

        target = self._choose_target()
        if target:
            best_direction = self._move_toward_target(target, walkable_neighbors)
            if best_direction:
                return best_direction

        for direction, cell in walkable_neighbors.items():
            position = tuple(cell["position"])
            if position not in self.state.belief["visited_positions"]:
                return direction

        return next(iter(walkable_neighbors), None)

    def _choose_target(self) -> tuple[int, int] | None:
        if "key" not in self.state.inventory and self.state.belief["key_position"]:
            return tuple(self.state.belief["key_position"])
        if "key" in self.state.inventory and self.state.belief["door_position"]:
            return tuple(self.state.belief["door_position"])
        if self.state.belief["exit_position"]:
            return tuple(self.state.belief["exit_position"])
        return None

    def _move_toward_target(
        self,
        target: tuple[int, int],
        walkable_neighbors: dict[str, dict[str, Any]],
    ) -> str | None:
        current_row, current_col = self.state.position
        best_choice = None
        best_distance = None

        for direction, cell in walkable_neighbors.items():
            next_row, next_col = cell["position"]
            distance = abs(target[0] - next_row) + abs(target[1] - next_col)
            if best_distance is None or distance < best_distance:
                best_distance = distance
                best_choice = direction

        if best_choice is None and target == (current_row, current_col):
            return None
        return best_choice

from __future__ import annotations

import random
import time
import uuid
from dataclasses import dataclass
from typing import Any

from agents import AgentState, DungeonAgent
from logger import SimulationLogger, StepLog
import tools


GRID_SIZE = 8
AGENT_IDS = ("A", "B")


@dataclass
class RunResult:
    summary: dict[str, Any]
    analysis_report: str
    trace_path: str


class DungeonSimulation:
    def __init__(self, seed: int = 7, max_steps: int = 80) -> None:
        self.seed = seed
        self.rng = random.Random(seed)
        self.max_steps = max_steps
        self.turn_index = 0
        self.message_queue: list[dict[str, Any]] = []

        self.walls: set[tuple[int, int]] = set()
        self.key_position = (0, 0)
        self.door_position = (0, 0)
        self.exit_position = (0, 0)
        self.key_picked = False
        self.door_unlocked = False

        self.agent_states: dict[str, AgentState] = {}
        self.agents: dict[str, DungeonAgent] = {}

        self.logger = SimulationLogger(run_id=f"run-{uuid.uuid4().hex[:8]}")
        self._build_world()
        self._build_agents()

    def _build_world(self) -> None:
        blocked = set()
        self.key_position = self._random_open_cell(blocked)
        blocked.add(self.key_position)
        self.door_position = self._random_open_cell(blocked)
        blocked.add(self.door_position)
        self.exit_position = self._random_open_cell(blocked)
        blocked.add(self.exit_position)

        wall_count = self.rng.randint(5, 8)
        while len(self.walls) < wall_count:
            candidate = self._random_open_cell(blocked | self.walls)
            self.walls.add(candidate)

    def _build_agents(self) -> None:
        occupied = {self.key_position, self.door_position, self.exit_position, *self.walls}
        for agent_id in AGENT_IDS:
            position = self._random_open_cell(occupied)
            occupied.add(position)
            state = AgentState(agent_id=agent_id, position=position)
            self.agent_states[agent_id] = state

        self.agents["A"] = DungeonAgent(self.agent_states["A"], teammate_id="B")
        self.agents["B"] = DungeonAgent(self.agent_states["B"], teammate_id="A")

    def _random_open_cell(self, blocked: set[tuple[int, int]]) -> tuple[int, int]:
        while True:
            candidate = (self.rng.randrange(GRID_SIZE), self.rng.randrange(GRID_SIZE))
            if candidate not in blocked:
                return candidate

    def in_bounds(self, position: tuple[int, int]) -> bool:
        row, col = position
        return 0 <= row < GRID_SIZE and 0 <= col < GRID_SIZE

    def get_visible_cells(self, agent_id: str) -> list[dict[str, Any]]:
        agent = self.agent_states[agent_id]
        visible = []
        for direction, delta in [("self", (0, 0)), *tools.DIRECTIONS.items()]:
            if direction == "self":
                row_delta, col_delta = delta
            else:
                row_delta, col_delta = delta
            position = (agent.position[0] + row_delta, agent.position[1] + col_delta)
            if not self.in_bounds(position):
                continue
            cell = self.describe_cell(position)
            cell["position"] = list(position)
            cell["direction"] = direction
            cell["is_walkable"] = self.is_walkable(position)
            visible.append(cell)
        return visible

    def describe_cell(self, position: tuple[int, int]) -> dict[str, Any]:
        if position in self.walls:
            return {"cell_type": "wall"}
        if position == self.key_position and not self.key_picked:
            return {"cell_type": "key"}
        if position == self.door_position:
            return {"cell_type": "door", "door_unlocked": self.door_unlocked}
        if position == self.exit_position:
            return {"cell_type": "exit"}
        for agent_id, state in self.agent_states.items():
            if state.position == position:
                return {"cell_type": "agent", "agent_id": agent_id}
        return {"cell_type": "empty"}

    def is_walkable(self, position: tuple[int, int]) -> bool:
        if position in self.walls:
            return False
        if position == self.door_position and not self.door_unlocked:
            return False
        return True

    def build_observation(self, agent_id: str) -> dict[str, Any]:
        state = self.agent_states[agent_id]
        delivered = self._deliver_messages(agent_id)
        visible_cells = self.get_visible_cells(agent_id)
        self.agents[agent_id].observe(visible_cells)
        return {
            "self_position": list(state.position),
            "inventory": list(state.inventory),
            "visible_cells": visible_cells,
            "received_messages": delivered,
        }

    def _deliver_messages(self, agent_id: str) -> list[dict[str, Any]]:
        delivered: list[dict[str, Any]] = []
        remaining: list[dict[str, Any]] = []
        for message in self.message_queue:
            if message["to"] == agent_id and message["deliver_on_turn"] <= self.turn_index:
                payload = {
                    "from": message["from"],
                    **message["message"],
                }
                self.agent_states[agent_id].inbox.append(payload)
                delivered.append(payload)
            else:
                remaining.append(message)
        self.message_queue = remaining
        return delivered

    def run(self, trace_path: str) -> RunResult:
        major_events: list[dict[str, Any]] = []

        for step in range(1, self.max_steps + 1):
            self.turn_index = step
            for agent_id in AGENT_IDS:
                observation = self.build_observation(agent_id)
                action = self.agents[agent_id].choose_action(observation)
                start = time.perf_counter()
                tool_output = self.execute_action(agent_id, action.tool, action.args)
                latency_ms = round((time.perf_counter() - start) * 1000, 3)
                self.agent_states[agent_id].note_action(action.tool)

                result_state = self.snapshot_agent_state(agent_id)
                ground_truth = self.snapshot_ground_truth()

                self.logger.log_step(
                    StepLog(
                        step=step,
                        agent_id=agent_id,
                        observation=observation,
                        thought=action.thought,
                        action=action.tool,
                        tool_input=action.args,
                        tool_output=tool_output,
                        result_state=result_state,
                        belief_state=dict(self.agent_states[agent_id].belief),
                        ground_truth=ground_truth,
                        delivered_messages=observation["received_messages"],
                        latency_ms=latency_ms,
                    )
                )

                event = self._capture_major_event(step, agent_id, tool_output)
                if event:
                    major_events.append(event)
                    self.logger.log_event(event)

                if self.is_success():
                    summary = self._build_summary(step, "success", major_events)
                    self.logger.export_json(trace_path, summary)
                    from logger import build_analysis_report

                    return RunResult(
                        summary=summary,
                        analysis_report=build_analysis_report(self.logger.history, summary),
                        trace_path=trace_path,
                    )

            if self._agents_stuck():
                summary = self._build_summary(step, "agents_stuck", major_events)
                self.logger.export_json(trace_path, summary)
                from logger import build_analysis_report

                return RunResult(
                    summary=summary,
                    analysis_report=build_analysis_report(self.logger.history, summary),
                    trace_path=trace_path,
                )

        summary = self._build_summary(self.max_steps, "max_steps_reached", major_events)
        self.logger.export_json(trace_path, summary)
        from logger import build_analysis_report

        return RunResult(
            summary=summary,
            analysis_report=build_analysis_report(self.logger.history, summary),
            trace_path=trace_path,
        )

    def execute_action(self, agent_id: str, tool_name: str, args: dict[str, Any]) -> dict[str, Any]:
        dispatch = {
            "move": lambda: tools.move(self, agent_id, args["direction"]),
            "look": lambda: tools.look(self, agent_id),
            "pick_up": lambda: tools.pick_up(self, agent_id, args["item"]),
            "check_inventory": lambda: tools.check_inventory(self, agent_id),
            "use_item": lambda: tools.use_item(self, agent_id, args["item"], args["target"]),
            "send_message": lambda: tools.send_message(self, agent_id, args["agent"], args["message"]),
        }
        return dispatch[tool_name]()

    def is_success(self) -> bool:
        return self.door_unlocked and all(
            state.position == self.exit_position for state in self.agent_states.values()
        )

    def _agents_stuck(self) -> bool:
        return all(
            len(state.recent_actions) >= 4 and len(set(state.recent_actions[-4:])) == 1
            for state in self.agent_states.values()
        )

    def snapshot_agent_state(self, agent_id: str) -> dict[str, Any]:
        state = self.agent_states[agent_id]
        return {
            "position": list(state.position),
            "inventory": list(state.inventory),
            "inbox_size": len(state.inbox),
        }

    def snapshot_ground_truth(self) -> dict[str, Any]:
        return {
            "key_position": list(self.key_position) if not self.key_picked else [-1, -1],
            "door_position": list(self.door_position),
            "door_unlocked": self.door_unlocked,
            "exit_position": list(self.exit_position),
            "agent_positions": {
                agent_id: list(state.position) for agent_id, state in self.agent_states.items()
            },
        }

    def _capture_major_event(
        self,
        step: int,
        agent_id: str,
        tool_output: dict[str, Any],
    ) -> dict[str, Any] | None:
        if tool_output.get("inventory") and "key" in tool_output["inventory"]:
            return {"step": step, "description": f"Agent {agent_id} picked up the key."}
        if tool_output.get("door_unlocked"):
            return {"step": step, "description": f"Agent {agent_id} unlocked the door."}
        if self.agent_states[agent_id].position == self.exit_position:
            return {"step": step, "description": f"Agent {agent_id} reached the exit."}
        return None

    def _build_summary(
        self,
        step_count: int,
        status: str,
        major_events: list[dict[str, Any]],
    ) -> dict[str, Any]:
        return {
            "status": status,
            "steps": step_count,
            "seed": self.seed,
            "door_unlocked": self.door_unlocked,
            "agents_at_exit": {
                agent_id: state.position == self.exit_position
                for agent_id, state in self.agent_states.items()
            },
            "major_events": major_events,
        }

    def render(self, step: int, latest_logs: list[StepLog]) -> str:
        grid = []
        for row in range(GRID_SIZE):
            cells = []
            for col in range(GRID_SIZE):
                position = (row, col)
                symbol = "."
                if position in self.walls:
                    symbol = "#"
                elif position == self.key_position and not self.key_picked:
                    symbol = "K"
                elif position == self.door_position:
